interface SMSArgs {
  phone: string;
  message: string;
  key: string;
}

interface SMSResult {
  success: boolean;
  error?: string;
  quotaRemaining?: number;
  textId?: string;
}

function normalizePhone(phone: string): string {
  // Strip all non-digits
  const digits = phone.replace(/\D/g, '');
  // US number: 10 digits → add +1, 11 digits starting with 1 → add +
  if (digits.length === 10) return `+1${digits}`;
  if (digits.length === 11 && digits.startsWith('1')) return `+${digits}`;
  // Already has country code or international
  return `+${digits}`;
}

export const handler = async (event: any): Promise<SMSResult> => {
  console.log('Full event:', JSON.stringify(event));

  // AppSync sends arguments in different shapes depending on config
  const args = event.arguments || event;
  const phone = args.phone;
  const message = args.message;
  const key = args.key;

  console.log('Parsed args - phone:', phone, 'message:', message?.substring(0, 20), 'key:', key ? 'present' : 'MISSING');

  if (!phone || !message || !key) {
    return {
      success: false,
      error: `Missing fields: phone=${!!phone}, message=${!!message}, key=${!!key}`,
    };
  }

  const normalizedPhone = normalizePhone(phone);
  console.log('Sending SMS to:', normalizedPhone, '(original:', phone, ')');

  try {
    const response = await fetch('https://textbelt.com/text', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ phone: normalizedPhone, message, key }),
    });

    const result = await response.json() as any;

    console.log('TextBelt full response:', JSON.stringify(result));

    return {
      success: result.success,
      error: result.error || `DEBUG: sent to ${normalizedPhone}, textId=${result.textId}`,
      quotaRemaining: result.quotaRemaining,
      textId: result.textId,
    };
  } catch (error) {
    console.error('SMS API error:', error);
    return {
      success: false,
      error: error instanceof Error ? error.message : 'SMS service unavailable',
    };
  }
};
